package com.example.oidcclient.security;

import com.example.oidcclient.config.OidcProperties;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.RequestEntity;
import org.springframework.http.converter.FormHttpMessageConverter;
import org.springframework.security.oauth2.client.endpoint.DefaultAuthorizationCodeTokenResponseClient;
import org.springframework.security.oauth2.client.endpoint.OAuth2AccessTokenResponseClient;
import org.springframework.security.oauth2.client.endpoint.OAuth2AuthorizationCodeGrantRequest;
import org.springframework.security.oauth2.client.http.OAuth2ErrorResponseErrorHandler;
import org.springframework.security.oauth2.core.endpoint.OAuth2AccessTokenResponse;
import org.springframework.security.oauth2.core.http.converter.OAuth2AccessTokenResponseHttpMessageConverter;
import org.springframework.stereotype.Component;
import org.springframework.web.client.RestTemplate;

import javax.net.ssl.SSLContext;
import javax.net.ssl.TrustManagerFactory;
import java.net.URI;
import java.security.KeyStore;
import java.util.Arrays;
import java.util.List;

@Component
public class SecureTokenResponseClient implements OAuth2AccessTokenResponseClient<OAuth2AuthorizationCodeGrantRequest> {

    private static final Logger logger = LoggerFactory.getLogger(SecureTokenResponseClient.class);

    private final DefaultAuthorizationCodeTokenResponseClient delegate;
    private final OidcProperties oidcProperties;

    // Allowlist of permitted token endpoint schemes
    private static final List<String> ALLOWED_SCHEMES = List.of("https");

    public SecureTokenResponseClient(OidcProperties oidcProperties) {
        this.oidcProperties = oidcProperties;
        this.delegate = new DefaultAuthorizationCodeTokenResponseClient();

        // Configure RestTemplate with secure settings
        RestTemplate restTemplate = createSecureRestTemplate();
        this.delegate.setRestOperations(restTemplate);
    }

    private RestTemplate createSecureRestTemplate() {
        RestTemplate restTemplate = new RestTemplate(Arrays.asList(
            new FormHttpMessageConverter(),
            new OAuth2AccessTokenResponseHttpMessageConverter()
        ));
        restTemplate.setErrorHandler(new OAuth2ErrorResponseErrorHandler());
        return restTemplate;
    }

    @Override
    public OAuth2AccessTokenResponse getTokenResponse(OAuth2AuthorizationCodeGrantRequest authorizationCodeGrantRequest) {
        // Validate the token endpoint URI before making the request
        String tokenUri = authorizationCodeGrantRequest
            .getClientRegistration()
            .getProviderDetails()
            .getTokenUri();

        validateTokenEndpointUri(tokenUri);

        logger.info("Exchanging authorization code for tokens at validated endpoint");

        OAuth2AccessTokenResponse response = delegate.getTokenResponse(authorizationCodeGrantRequest);

        logger.info("Successfully obtained token response");

        return response;
    }

    /**
     * Validates the token endpoint URI to prevent SSRF and ensure
     * communication only occurs over HTTPS to trusted endpoints.
     */
    private void validateTokenEndpointUri(String tokenUri) {
        if (tokenUri == null || tokenUri.isBlank()) {
            throw new SecurityException("Token endpoint URI must not be null or empty");
        }

        URI uri;
        try {
            uri = URI.create(tokenUri);
        } catch (IllegalArgumentException e) {
            throw new SecurityException("Invalid token endpoint URI: " + e.getMessage());
        }

        // Enforce HTTPS only - prevents token leakage over unencrypted connections
        String scheme = uri.getScheme();
        if (scheme == null || !ALLOWED_SCHEMES.contains(scheme.toLowerCase())) {
            throw new SecurityException(
                "Token endpoint must use HTTPS. Received scheme: " + scheme
            );
        }

        // Validate against configured allowed token endpoint
        String configuredEndpoint = oidcProperties.getTokenEndpoint();
        if (configuredEndpoint != null && !configuredEndpoint.isBlank()) {
            URI configuredUri = URI.create(configuredEndpoint);
            if (!uri.getHost().equalsIgnoreCase(configuredUri.getHost())) {
                throw new SecurityException(
                    "Token endpoint host does not match configured endpoint. " +
                    "Expected host: " + configuredUri.getHost() + ", got: " + uri.getHost()
                );
            }
        }

        // Prevent SSRF to internal networks
        String host = uri.getHost();
        if (host == null) {
            throw new SecurityException("Token endpoint must have a valid host");
        }

        // Block private/internal IP ranges and localhost
        if (isInternalHost(host)) {
            throw new SecurityException(
                "Token endpoint must not point to internal/private network addresses"
            );
        }

        logger.debug("Token endpoint URI validated successfully: {}", uri.getHost());
    }

    /**
     * Checks if the host resolves to an internal/private network address.
     */
    private boolean isInternalHost(String host) {
        String lowerHost = host.toLowerCase();

        // Block localhost variants
        if (lowerHost.equals("localhost") || lowerHost.equals("127.0.0.1") ||
            lowerHost.equals("::1") || lowerHost.equals("0.0.0.0")) {
            return true;
        }

        // Block common internal hostnames
        if (lowerHost.endsWith(".local") || lowerHost.endsWith(".internal")) {
            return true;
        }

        // Block private IP ranges
        if (host.startsWith("10.") || host.startsWith("192.168.") ||
            host.startsWith("172.16.") || host.startsWith("172.17.") ||
            host.startsWith("172.18.") || host.startsWith("172.19.") ||
            host.startsWith("172.20.") || host.startsWith("172.21.") ||
            host.startsWith("172.22.") || host.startsWith("172.23.") ||
            host.startsWith("172.24.") || host.startsWith("172.25.") ||
            host.startsWith("172.26.") || host.startsWith("172.27.") ||
            host.startsWith("172.28.") || host.startsWith("172.29.") ||
            host.startsWith("172.30.") || host.startsWith("172.31.") ||
            host.startsWith("169.254.") || host.startsWith("fc00:") ||
            host.startsWith("fd") || host.startsWith("fe80:")) {
            return true;
        }

        // Block metadata endpoints (cloud environments)
        if (lowerHost.equals("metadata.google.internal") ||
            host.equals("169.254.169.254")) {
            return true;
        }

        return false;
    }
}

