package com.example.oidcclient.security;

import com.example.oidcclient.config.OidcProperties;
import com.example.oidcclient.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserRequest;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserService;
import org.springframework.security.oauth2.core.OAuth2AuthenticationException;
import org.springframework.security.oauth2.core.OAuth2Error;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.security.oauth2.core.oidc.user.DefaultOidcUser;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Component;

import java.time.Instant;
import java.util.*;

@Component
public class CustomOidcUserService extends OidcUserService {

    private static final Logger logger = LoggerFactory.getLogger(CustomOidcUserService.class);

    private final OidcProperties oidcProperties;
    private final UserSessionManager userSessionManager;

    public CustomOidcUserService(OidcProperties oidcProperties, UserSessionManager userSessionManager) {
        this.oidcProperties = oidcProperties;
        this.userSessionManager = userSessionManager;
    }

    @Override
    public OidcUser loadUser(OidcUserRequest userRequest) throws OAuth2AuthenticationException {
        OidcUser oidcUser = super.loadUser(userRequest);

        // Validate the ID token claims
        OidcIdToken idToken = oidcUser.getIdToken();
        validateIdTokenClaims(idToken);

        // Extract and map authorities from claims
        Set<GrantedAuthority> authorities = extractAuthorities(oidcUser);

        // Create user session from validated claims
        UserSession userSession = createUserSession(idToken, oidcUser);
        userSessionManager.storeSession(userSession);

        logger.info("Successfully authenticated user: {} (sub: {})",
            sanitizeLogInput(userSession.getDisplayName()),
            sanitizeLogInput(userSession.getSubject()));

        // Return enriched OidcUser with mapped authorities
        return new DefaultOidcUser(
            authorities,
            idToken,
            oidcUser.getUserInfo(),
            "sub"
        );
    }

    /**
     * Validates critical ID token claims to ensure token integrity and authenticity.
     */
    private void validateIdTokenClaims(OidcIdToken idToken) {
        // Validate issuer against allowlist
        String issuer = idToken.getIssuer() != null ? idToken.getIssuer().toString() : null;
        if (issuer == null || !oidcProperties.getAllowedIssuers().contains(issuer)) {
            logger.warn("ID token issuer validation failed. Issuer: {}", sanitizeLogInput(issuer));
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_id_token", "ID token issuer is not trusted", null)
            );
        }

        // Validate audience contains our client ID
        List<String> audience = idToken.getAudience();
        String expectedAudience = oidcProperties.getExpectedAudience();
        if (audience == null || !audience.contains(expectedAudience)) {
            logger.warn("ID token audience validation failed");
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_id_token", "ID token audience does not match expected client", null)
            );
        }

        // Validate token is not expired
        Instant expiresAt = idToken.getExpiresAt();
        if (expiresAt == null || Instant.now().isAfter(expiresAt)) {
            logger.warn("ID token has expired");
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_id_token", "ID token has expired", null)
            );
        }

        // Validate issued-at is not in the future (with small clock skew tolerance)
        Instant issuedAt = idToken.getIssuedAt();
        if (issuedAt != null && issuedAt.isAfter(Instant.now().plusSeconds(60))) {
            logger.warn("ID token issued-at is in the future");
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_id_token", "ID token issued-at is in the future", null)
            );
        }

        // Validate subject claim exists
        String subject = idToken.getSubject();
        if (subject == null || subject.isBlank()) {
            logger.warn("ID token missing subject claim");
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_id_token", "ID token missing subject claim", null)
            );
        }

        // Validate nonce if present (Spring Security handles this, but double-check)
        // The nonce validation is handled by Spring Security's OidcAuthorizationCodeAuthenticationProvider

        logger.debug("ID token claims validated successfully for subject: {}", sanitizeLogInput(subject));
    }

    /**
     * Extracts and maps authorities from OIDC claims.
     */
    private Set<GrantedAuthority> extractAuthorities(OidcUser oidcUser) {
        Set<GrantedAuthority> authorities = new LinkedHashSet<>();
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        // Map roles from claims if present
        Object rolesClaim = oidcUser.getIdToken().getClaim("roles");
        if (rolesClaim instanceof Collection<?>) {
            for (Object role : (Collection<?>) rolesClaim) {
                if (role instanceof String) {
                    String sanitizedRole = ((String) role).replaceAll("[^a-zA-Z0-9_]", "");
                    if (!sanitizedRole.isBlank()) {
                        authorities.add(new SimpleGrantedAuthority("ROLE_" + sanitizedRole.toUpperCase()));
                    }
                }
            }
        }

        // Map groups from claims if present
        Object groupsClaim = oidcUser.getIdToken().getClaim("groups");
        if (groupsClaim instanceof Collection<?>) {
            for (Object group : (Collection<?>) groupsClaim) {
                if (group instanceof String) {
                    String sanitizedGroup = ((String) group).replaceAll("[^a-zA-Z0-9_]", "");
                    if (!sanitizedGroup.isBlank()) {
                        authorities.add(new SimpleGrantedAuthority("GROUP_" + sanitizedGroup.toUpperCase()));
                    }
                }
            }
        }

        return authorities;
    }

    /**
     * Creates a user session from validated ID token claims.
     */
    private UserSession createUserSession(OidcIdToken idToken, OidcUser oidcUser) {
        UserSession session = new UserSession();
        session.setSubject(idToken.getSubject());
        session.setIssuer(idToken.getIssuer() != null ? idToken.getIssuer().toString() : null);
        session.setEmail(idToken.getEmail());
        session.setEmailVerified(idToken.getEmailVerified() != null ? idToken.getEmailVerified() : false);

        // Safely extract display name
        String name = idToken.getFullName();
        if (name == null || name.isBlank()) {
            name = idToken.getPreferredUsername();
        }
        if (name == null || name.isBlank()) {
            name = idToken.getSubject();
        }
        session.setDisplayName(name);

        session.setIssuedAt(idToken.getIssuedAt());
        session.setExpiresAt(idToken.getExpiresAt());
        session.setSessionId(UUID.randomUUID().toString());
        session.setCreatedAt(Instant.now());

        return session;
    }

    /**
     * Sanitizes input for safe logging to prevent log injection.
     */
    private String sanitizeLogInput(String input) {
        if (input == null) {
            return "null";
        }
        return input.replaceAll("[\\r\\n\\t]", "_")
                     .replaceAll("[^\\x20-\\x7E]", "?");
    }
}

