package com.example.oidcclient.security;

import com.example.oidcclient.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;

import java.time.Instant;
import java.util.concurrent.ConcurrentHashMap;

@Component
public class UserSessionManager {

    private static final Logger logger = LoggerFactory.getLogger(UserSessionManager.class);

    private final ConcurrentHashMap<String, UserSession> sessions = new ConcurrentHashMap<>();

    public void storeSession(UserSession session) {
        if (session == null || session.getSessionId() == null) {
            throw new IllegalArgumentException("Session and session ID must not be null");
        }
        sessions.put(session.getSessionId(), session);
        logger.debug("Stored session for subject: {}", session.getSubject());
    }

    public UserSession getSession(String sessionId) {
        if (sessionId == null) {
            return null;
        }
        UserSession session = sessions.get(sessionId);
        if (session != null && session.getExpiresAt() != null &&
            Instant.now().isAfter(session.getExpiresAt())) {
            sessions.remove(sessionId);
            logger.debug("Removed expired session: {}", sessionId);
            return null;
        }
        return session;
    }

    public void removeSession(String sessionId) {
        if (sessionId != null) {
            sessions.remove(sessionId);
            logger.debug("Removed session: {}", sessionId);
        }
    }

    public void cleanupExpiredSessions() {
        Instant now = Instant.now();
        sessions.entrySet().removeIf(entry -> {
            UserSession session = entry.getValue();
            return session.getExpiresAt() != null && now.isAfter(session.getExpiresAt());
        });
    }
}

