@Controller
public class AuthErrorController {

    @GetMapping("/auth-error")
    public String authError(@RequestParam(required = false) String error, Model model) {
        // Do NOT reflect the error parameter directly - use a safe mapped message
        String safeMessage = mapErrorToSafeMessage(error);
        model.addAttribute("errorMessage", safeMessage);
        return "auth-error";
    }

    private String mapErrorToSafeMessage(String error) {
        if (error == null) {
            return "An authentication error occurred.";
        }
        return switch (error) {
            case "invalid_token" -> "The authentication token was invalid. Please try again.";
            case "access_denied" -> "Access was denied. Please contact your administrator.";
            case "expired" -> "Your session has expired. Please log in again.";
            default -> "An authentication error occurred. Please try again.";
        };
    }
}

