package com.example.oidcclient.config;

import com.example.oidcclient.security.UserSessionManager;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.scheduling.annotation.EnableScheduling;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;

@Component
@EnableScheduling
public class SessionCleanupScheduler {

    private static final Logger logger = LoggerFactory.getLogger(SessionCleanupScheduler.class);

    private final UserSessionManager userSessionManager;

    public SessionCleanupScheduler(UserSessionManager userSessionManager) {
        this.userSessionManager = userSessionManager;
    }

    @Scheduled(fixedRate = 300000) // Every 5 minutes
    public void cleanupExpiredSessions() {
        logger.debug("Running expired session cleanup");
        userSessionManager.cleanupExpiredSessions();
    }
}